#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        for(int i=1;i<=N;i++){
            int val = i ^ (i-1);
            if(i>1) putchar(' ');
            printf("%d",val);
        }
        putchar('\n');
    }
    return 0;
}

